@Database( entities = [ UsuarioEntity::class, MateriaEntity::class, ProfesorEntity::class, HorarioEntity::class, ImagenEntity::class, SyncQueueEntity::class ], version = 3, exportSchema = false ) @TypeConverters(Converters::class) abstract class AppDatabase : RoomDatabase() { abstract fun materiaDao(): MateriaDao abstract fun profesorDao(): ProfesorDao abstract fun horarioDao(): HorarioDao abstract fun imagenDao(): ImagenDao abstract fun usuarioDao(): UsuarioDao abstract fun syncQueueDao(): SyncQueueDao
